import { Component, OnInit } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-candidate-applied-list',
  template: `
  <div class="page">
    <div class="page-header">
      <div>
        <h1 class="page-title">My Applications</h1>
        <p class="muted">All internships you've applied to</p>
      </div>
      <div>
        <button class="btn btn-ghost" (click)="router.navigate(['/candidate/dashboard'])">Back</button>
        <button class="btn btn-black" (click)="logout()">Logout</button>
      </div>
    </div>

    <div class="card-grid" style="margin-top:14px">
      <div *ngFor="let app of applications" class="card-item square-card">
        <h3 style="text-align:center;color:var(--text)">{{ getInternship(app)?.companyName }}</h3>
        <h4 style="margin:6px 0">{{ getInternship(app)?.title }}</h4>
        <p class="muted">Status: {{ app.status || 'N/A' }}</p>
        <div style="margin-top:10px;display:flex;gap:8px;justify-content:center">
          <button class="btn" (click)="openDetail(app.id)">Access</button>
        </div>
      </div>
    </div>
  </div>
  `,
  styles: [`.square-card{height:210px;display:flex;flex-direction:column;justify-content:space-between}`]
})
export class CandidateAppliedListComponent implements OnInit {
  applications: any[] = [];
  internships: any[] = [];

  constructor(public auth: AuthService, private http: HttpClient, public router: Router) {}

  ngOnInit() { this.fetchApplications(); this.fetchInternships(); }

  logout() { this.auth.logout(); this.router.navigate(['/']); }

  async fetchApplications() {
    try { const res: any = await this.http.get<any[]>('http://localhost:8080/api/applications').toPromise(); this.applications = res.filter((a: any) => a.email === this.auth.user?.email); } catch (err) { console.error(err); }
  }

  async fetchInternships() { try { this.internships = await this.http.get<any[]>('http://localhost:8080/api/internships').toPromise(); } catch (err) { console.error(err); } }

  getInternship(app: any) { return this.internships.find(i => i.id === app.internshipId) || { companyName: 'Unknown', title: 'Role' }; }

  openDetail(id: any) { this.router.navigate(['/candidate/application', id]); }
}
